using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly ILogger<ModelTrainerService> _logger;

    public ModelTrainerService(ILogger<ModelTrainerService> logger)
    {
        _logger = logger;
    }

    public string TrainAndSave(string dataPath, string modelPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text
            .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var report = $"""
            === Model Evaluation Metrics ===
            MacroAccuracy:    {metrics.MacroAccuracy:F4}
            MicroAccuracy:    {metrics.MicroAccuracy:F4}
            LogLoss:          {metrics.LogLoss:F4}
            LogLossReduction: {metrics.LogLossReduction:F4}
            """;

        _logger.LogInformation("{Metrics}", report);

        _mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);

        return report;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainerService _trainer;

    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    public TicketController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainerService trainer)
    {
        _predictionPool = predictionPool;
        _trainer = trainer;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < Categories.Length && i < prediction.Score.Length; i++)
            confidence[Categories[i]] = prediction.Score[i];

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpPost("train")]
    public ActionResult Train()
    {
        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");

        var report = _trainer.TrainAndSave(dataPath, modelPath);
        return Ok(new { message = "Model trained successfully.", metrics = report });
    }
}

